// C# — Binary Search (Iterative)
int[] arr = { 5, 12, 23, 37, 45, 56, 70, 89, 95 };
int target = 45;

int left = 0;
int right = arr.Length - 1;
int result = -1;

while (left <= right)
{
    int mid = left + (right - left) / 2;

    if (arr[mid] == target)
    {
        result = mid;
        break;
    }
    else if (arr[mid] < target)
    {
        left = mid + 1;
    }
    else
    {
        right = mid - 1;
    }
}

// result = 4 (index of 45)

// C++ — Binary Search (Iterative)
#include <iostream>
using namespace std;

int main() {
    int arr[] = {5, 12, 23, 37, 45, 56, 70, 89, 95};
    int size = 9;
    int target = 45;

    int left = 0;
    int right = size - 1;
    int result = -1;

    while (left <= right) {
        int mid = left + (right - left) / 2;

        if (arr[mid] == target) {
            result = mid;
            break;
        } else if (arr[mid] < target) {
            left = mid + 1;
        } else {
            right = mid - 1;
        }
    }

    // result = 4 (index of 45)
    return 0;
}

