// JavaScript — Binary Search (Iterative)
const arr = [5, 12, 23, 37, 45, 56, 70, 89, 95];
const target = 45;

let left = 0;
let right = arr.length - 1;
let result = -1;

while (left <= right) {
    const mid = Math.floor((left + right) / 2);

    if (arr[mid] === target) {
        result = mid;
        break;
    } else if (arr[mid] < target) {
        left = mid + 1;
    } else {
        right = mid - 1;
    }
}

// result = 4 (index of 45)
